class Solution:
    def findPrimePairs(self, n: int) -> List[List[int]]:
        def is_prime(num):
            if num <= 1:
                return False
            for i in range(2, int(num**0.5) + 1):
                if num % i == 0:
                    return False
            return True
        result = []
        for i in range(2, n // 2 + 1):
            if is_prime(i) and is_prime(n - i):
                result.append([i, n - i])
        return sorted(result)    
