class Solution:
    def colorTheArray(self, n: int, queries: List[List[int]]) -> List[int]:
        arr = [0] * n
        result = []
        for i in range(len(queries)):
            index, color = queries[i]
            arr[index] = color
            count = 0
            for j in range(n - 1):
                if arr[j] == arr[j + 1] and arr[j] != 0:
                    count += 1
            result.append(count)
        return result   
